import React, { useState, useEffect } from "react";
import ReactDOM from "react-dom";
import axios from "axios";
import {
  Card,
  CardHeader,
  CardTitle,
  CardContent,
  Input,
  Button,
  Label,
  Loader2,
} from "./ui/UIComponents";
import {
  Table,
  TableHeader,
  TableBody,
  TableRow,
  TableHead,
  TableCell,
} from "./ui/Table";
import { updateMenuItem } from "../services/api";
import { API, toast, safeGet, safeArray } from "../utils/helpers";

export default function FoodMenu({ mode }) {
  const [items, setItems] = useState([]);
  const [loading, setLoading] = useState(false);
  const [newItem, setNewItem] = useState({
    name: "",
    alpha_code: "",
    numeric_code: "",
    price_fixed: "",
    price_general: "",
    price_ac: "",
    category: "",
  });

  const [searchTerm, setSearchTerm] = useState("");

  const filteredItems = items.filter((item) => {
    const term = searchTerm.toLowerCase();
    return (
      (item.name || "").toLowerCase().includes(term) ||
      (item.alpha_code || "").toLowerCase().includes(term) ||
      (item.numeric_code || "").toString().includes(term) ||
      (item.category || "").toString().toLowerCase().includes(term)
    );
  });

  // ... (load function remains same)

  // ... (renderEditModal remains same)

  // ...

  return (
    <Card>
      <CardHeader>
        <CardTitle>Food Menu ({items.length} items)</CardTitle>
        <div className="mt-2">
          <Input
            placeholder="Search items..."
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            className="max-w-sm"
          />
        </div>
      </CardHeader>
      <CardContent>
        {mode === "admin-full" && (
          <div className="grid grid-cols-4 gap-4 mb-6 p-4 bg-gray-50 rounded-lg">
            <Input
              name="name"
              placeholder="Item Name"
              value={newItem.name}
              onChange={handleNewItemChange}
            />
            <Input
              name="alpha_code"
              placeholder="Alpha Code"
              value={newItem.alpha_code}
              onChange={handleNewItemChange}
            />
            <Input
              name="numeric_code"
              placeholder="Numeric Code"
              value={newItem.numeric_code}
              onChange={handleNewItemChange}
            />
            <Input
              name="category"
              placeholder="Category"
              value={newItem.category}
              onChange={handleNewItemChange}
            />
            <Input
              name="price_fixed"
              type="number"
              step="0.01"
              placeholder="Fixed Price"
              value={newItem.price_fixed}
              onChange={handleNewItemChange}
            />
            <Input
              name="price_general"
              type="number"
              step="0.01"
              placeholder="General Price"
              value={newItem.price_general}
              onChange={handleNewItemChange}
            />
            <Input
              name="price_ac"
              type="number"
              step="0.01"
              placeholder="AC Price"
              value={newItem.price_ac}
              onChange={handleNewItemChange}
            />
            <Input
              name="quantity"
              type="number"
              placeholder="Qty (for Category JSON)"
              value={newItem.quantity || ""}
              onChange={handleNewItemChange}
            />
            <Button onClick={handleAddItem} className="col-span-4">
              + Add Item
            </Button>
          </div>
        )}

        {filteredItems.length === 0 ? (
          <div className="text-center py-8 text-gray-500">
            {searchTerm
              ? `No items found matching "${searchTerm}"`
              : "No menu items found."}
          </div>
        ) : (
          <Table>
            <TableHeader>
              <TableRow>
                <TableHead>Item Name</TableHead>
                <TableHead>Alpha Code</TableHead>
                <TableHead>Numeric Code</TableHead>
                <TableHead>Fixed Price</TableHead>
                <TableHead>General Price</TableHead>
                <TableHead>AC Price</TableHead>
                <TableHead>Category</TableHead>
                {mode === "admin-full" && <TableHead>Actions</TableHead>}
              </TableRow>
            </TableHeader>
            <TableBody>
              {filteredItems.map((item) => {
                const safeRender = (val, def = "-") => {
                  if (val === null || val === undefined) return def;
                  if (typeof val === "object") {
                    return val.name || val.item_name || JSON.stringify(val);
                  }
                  return val;
                };

                return (
                  <TableRow key={safeGet(item, "id", Math.random())}>
                    <TableCell>
                      {safeRender(safeGet(item, "name"), "N/A")}
                    </TableCell>
                    <TableCell>
                      {safeRender(safeGet(item, "alpha_code"), "-")}
                    </TableCell>
                    <TableCell>
                      {safeRender(safeGet(item, "numeric_code"), "-")}
                    </TableCell>
                    <TableCell>
                      {Number(safeGet(item, "price_fixed", 0)).toFixed(2)}
                    </TableCell>
                    <TableCell>
                      {Number(safeGet(item, "price_general", 0)).toFixed(2)}
                    </TableCell>
                    <TableCell>
                      {Number(safeGet(item, "price_ac", 0)).toFixed(2)}
                    </TableCell>
                    <TableCell>
                      {(() => {
                        const raw = safeGet(item, "category");
                        if (!raw) return "-";

                        let display = String(raw);

                        if (typeof raw === "object") {
                          if (Array.isArray(raw) && raw.length > 0) {
                            display =
                              raw[0].name || raw[0].item_name || display;
                          } else if (!Array.isArray(raw)) {
                            display = raw.name || raw.item_name || display;
                          }
                        } else if (typeof raw === "string") {
                          try {
                            if (
                              raw.trim().startsWith("[") ||
                              raw.trim().startsWith("{")
                            ) {
                              const parsed = JSON.parse(raw);
                              if (Array.isArray(parsed) && parsed.length > 0) {
                                display =
                                  parsed[0].name ||
                                  parsed[0].item_name ||
                                  display;
                              } else if (parsed && typeof parsed === "object") {
                                display =
                                  parsed.name || parsed.item_name || display;
                              }
                            }
                          } catch (e) {
                            const match = raw.match(
                              /["']name["']\s*:\s*["']([^"']+)["']/i,
                            );
                            if (match && match[1]) display = match[1];
                          }
                        }

                        if (
                          display.startsWith("[") &&
                          display.includes("name")
                        ) {
                          const match = display.match(
                            /["']name["']\s*:\s*["']([^"']+)["']/i,
                          );
                          if (match && match[1]) display = match[1];
                        }

                        return display;
                      })()}
                    </TableCell>
                    {mode === "admin-full" && (
                      <TableCell>
                        <div style={{ display: "flex", gap: 8 }}>
                          <Button
                            variant="outline"
                            size="sm"
                            onClick={() => {
                              setEditingItem({
                                id: safeGet(item, "id"),
                                name: safeGet(item, "name", ""),
                                alpha_code: safeGet(item, "alpha_code", ""),
                                numeric_code: safeGet(item, "numeric_code", ""),
                                price_fixed: safeGet(item, "price_fixed", 0),
                                price_general: safeGet(
                                  item,
                                  "price_general",
                                  0,
                                ),
                                price_ac: safeGet(item, "price_ac", 0),
                                category: safeGet(item, "category", ""),
                              });
                            }}
                          >
                            Edit
                          </Button>
                          <Button
                            variant="destructive"
                            size="sm"
                            onClick={() =>
                              handleDeleteItem(safeGet(item, "id"))
                            }
                          >
                            X
                          </Button>
                        </div>
                      </TableCell>
                    )}
                  </TableRow>
                );
              })}
            </TableBody>
          </Table>
        )}
        {renderEditModal()}
      </CardContent>
    </Card>
  );
}
